from flask import Flask, request, Response
from prometheus_client import Counter, generate_latest, CONTENT_TYPE_LATEST

app = Flask(__name__)

request_counters = {}

def get_counter(user_id: str, path: str) -> Counter:
    metric_name = f"http_requests_user_{user_id}_path_" + "".join(
        c if c.isalnum() else "_" for c in path
    ).strip("_").lower()
    if not metric_name or metric_name[0].isdigit():
        metric_name = f"metric_{metric_name}"
    if metric_name not in request_counters:
        request_counters[metric_name] = Counter(
            metric_name,
            f"HTTP requests for user_id={user_id}, path={path}",
            ["session_id", "full_path"],
        )
    return request_counters[metric_name]

@app.before_request
def track_request():
    if request.path == "/metrics":
        return
    user_id = request.headers.get("X-User-Id", "unknown")
    session_id = request.headers.get("X-Session-Id", "unknown")
    full_path = request.full_path.rstrip("?")
    counter = get_counter(user_id, request.path)
    counter.labels(session_id=session_id, full_path=full_path).inc()

@app.route("/")
def index():
    return "OK"

@app.route("/hello/<name>")
def hello(name):
    return f"Hello, {name}!"

@app.route("/metrics")
def metrics():
    return Response(generate_latest(), mimetype=CONTENT_TYPE_LATEST)

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=8000)